// jsPDF font definition for Courier Prime
// Generated by convert-font.js
// Font file: CourierPrime-Bold.ttf
// Font name: Courier Prime, Style: bold

export const fontData = '';

export const fontName = 'Courier Prime';
export const fontStyle = 'bold';
export const fileName = 'Courier Prime-bold.ttf';

export default function registerFont(doc) {
  if (!doc) {
    console.warn('jsPDF document not provided');
    return;
  }

  try {
    // Add font file to VFS
    doc.addFileToVFS(fileName, fontData);

    // Register font with jsPDF
    doc.addFont(fileName, fontName, fontStyle);

    // Set as active font
    doc.setFont(fontName);
  } catch (error) {
    console.error('Failed to register font:', error);
    throw error;
  }
}
